import{_ as e,c as t,o as a,a4 as n}from"./chunks/framework.ttppV29E.js";const o="/assets/aireglu-endpoint-request.BpbwqY2W.png",r="/assets/aireglu-endpoint-request-options.bcKXopEp.png",i="/assets/aireglu-endpoint-request-resync.CVcsIRaq.png",f=JSON.parse('{"title":"AireGlu Endpoint Request Task","description":"","frontmatter":{},"headers":[],"relativePath":"docs/endpoints/aireglu-endpoint-request.md","filePath":"docs/endpoints/aireglu-endpoint-request.md","lastUpdated":1771508773000}'),s={name:"docs/endpoints/aireglu-endpoint-request.md"},u=n('<h1 id="aireglu-endpoint-request-task" tabindex="-1">AireGlu Endpoint Request Task <a class="header-anchor" href="#aireglu-endpoint-request-task" aria-label="Permalink to &quot;AireGlu Endpoint Request Task&quot;">​</a></h1><p>The AireGlu Endpoint Request task is used to easily make calls to your other endpoints without the need to use the <a href="./http-request.html">HTTP Request</a>. Many of the concepts will already be familiar to you if you have used the <a href="./http-request.html">HTTP Request</a> task in the past.</p><h3 id="creating-a-request" tabindex="-1">Creating a Request <a class="header-anchor" href="#creating-a-request" aria-label="Permalink to &quot;Creating a Request&quot;">​</a></h3><p>Select the target endpoint you would like to call from the dropdown, and this will pull in the relevant configuration details such as version options, schema, as well as any required authentication for you to fill in.</p><p><img src="'+o+'" alt="AireGluEndpointRequestTask"></p><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><p>Depending on your referenced endpoint, you may need to click on the Authentication tab and fill in the relevant required authentication settings.</p><h3 id="request-options" tabindex="-1">Request Options <a class="header-anchor" href="#request-options" aria-label="Permalink to &quot;Request Options&quot;">​</a></h3><p><img src="'+r+'" alt="AireGluEndpointRequestOptions"></p><h2 id="headers" tabindex="-1">Headers <a class="header-anchor" href="#headers" aria-label="Permalink to &quot;Headers&quot;">​</a></h2><p>Some headers will be automatically added, such as content-type, which will correspond to the format of request body</p><p>Some requests may require additional headers to work correctly. By clicking on the Request Options tab, you will be able to add headers to the request. The <code>Header Name</code> field contains the Key, and one or more values can be added.</p><h2 id="query-parameters" tabindex="-1">Query Parameters <a class="header-anchor" href="#query-parameters" aria-label="Permalink to &quot;Query Parameters&quot;">​</a></h2><p>Similarly to headers, you may also want to add some query parameters to your request. This can easily be done in the same way as you would add a header, by going to the Request Options tab and adding the parameters as key-value pairs.</p><h3 id="resyncing" tabindex="-1">Resyncing <a class="header-anchor" href="#resyncing" aria-label="Permalink to &quot;Resyncing&quot;">​</a></h3><p>Whenever changes are made to the endpoint you are referencing, you will see a warning that you need to sync the latest changes. This could be something such as a schema change or authentication change.</p><p><img src="'+i+'" alt="AireGluEndpointRequestResync"></p><h3 id="further-information" tabindex="-1">Further information <a class="header-anchor" href="#further-information" aria-label="Permalink to &quot;Further information&quot;">​</a></h3><ul><li>Limitations: Retry on failure and status code retention are not currently supported (both are off by default).</li><li>Environment-aware URLs: The request URL is determined by the selected endpoint and it&#39;s current environment, so exporting/importing between environments (e.g. staging to production) works without manually updating URLs.</li></ul>',19),d=[u];function l(h,c,p,m,q,y){return a(),t("div",null,d)}const b=e(s,[["render",l]]);export{f as __pageData,b as default};
